# Token exchange: user sends their OAuth access token, agent uses it for downstream calls
from anthropic import Anthropic
import httpx, json

client = Anthropic()

def get_github_user(access_token: str) -> dict:
    """Verify the GitHub token and return the authenticated user's profile."""
    resp = httpx.get(
        "https://api.github.com/user",
        headers={"Authorization": f"Bearer {access_token}", "Accept": "application/vnd.github+json"},
        timeout=5,
    )
    resp.raise_for_status()
    return resp.json()

def make_github_tools(access_token: str) -> list[dict]:
    """Return tool definitions that close over the user's access token."""
    return [
        {
            "name": "list_repos",
            "description": "List the authenticated user's repositories.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "visibility": {"type": "string", "enum": ["all", "public", "private"], "default": "all"}
                },
            },
        },
        {
            "name": "create_issue",
            "description": "Create a GitHub issue in a repository.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "owner": {"type": "string"},
                    "repo": {"type": "string"},
                    "title": {"type": "string"},
                    "body": {"type": "string"},
                },
                "required": ["owner", "repo", "title"],
            },
        },
    ]

def execute_github_tool(name: str, inputs: dict, access_token: str) -> str:
    headers = {"Authorization": f"Bearer {access_token}", "Accept": "application/vnd.github+json"}
    if name == "list_repos":
        resp = httpx.get(
            "https://api.github.com/user/repos",
            params={"visibility": inputs.get("visibility", "all"), "per_page": 10},
            headers=headers, timeout=10,
        )
        resp.raise_for_status()
        return json.dumps([{"name": r["full_name"], "private": r["private"]} for r in resp.json()])
    if name == "create_issue":
        resp = httpx.post(
            f"https://api.github.com/repos/{inputs['owner']}/{inputs['repo']}/issues",
            json={"title": inputs["title"], "body": inputs.get("body", "")},
            headers=headers, timeout=10,
        )
        resp.raise_for_status()
        return json.dumps({"url": resp.json()["html_url"]})
    return "Unknown tool"

def github_agent(user_message: str, access_token: str) -> str:
    gh_user = get_github_user(access_token)   # validate token and get login
    tools = make_github_tools(access_token)
    messages = [{"role": "user", "content": user_message}]
    system = f"You are a GitHub assistant for {gh_user['login']}. Use tools to help with repositories and issues."
    while True:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=600,
            tools=tools,
            system=system,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next((b.text for b in resp.content if b.type == "text"), "")
        tool_results = []
        for block in resp.content:
            if block.type == "tool_use":
                result = execute_github_tool(block.name, block.input, access_token)
                tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages += [{"role": "assistant", "content": resp.content},
                      {"role": "user", "content": tool_results}]

