# Define all available tools with their required roles
ALL_TOOLS = {
    "search_knowledge_base": {
        "roles": ["viewer", "editor", "admin"],
        "definition": {
            "name": "search_knowledge_base",
            "description": "Search the internal knowledge base.",
            "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]},
        },
    },
    "create_ticket": {
        "roles": ["editor", "admin"],
        "definition": {
            "name": "create_ticket",
            "description": "Create a support ticket.",
            "input_schema": {
                "type": "object",
                "properties": {"title": {"type": "string"}, "description": {"type": "string"}},
                "required": ["title", "description"],
            },
        },
    },
    "delete_record": {
        "roles": ["admin"],
        "definition": {
            "name": "delete_record",
            "description": "Permanently delete a record.",
            "input_schema": {"type": "object", "properties": {"record_id": {"type": "string"}}, "required": ["record_id"]},
        },
    },
}

def get_tools_for_user(user) -> list[dict]:
    """Return only tool definitions the user is allowed to call."""
    permitted = []
    for tool_name, config in ALL_TOOLS.items():
        if any(role in user.roles for role in config["roles"]):
            permitted.append(config["definition"])
    return permitted

def check_tool_permission(tool_name: str, user) -> bool:
    """Double-check at execution time (defense in depth)."""
    config = ALL_TOOLS.get(tool_name)
    if config is None:
        return False
    return any(role in user.roles for role in config["roles"])

from anthropic import Anthropic
import json

client = Anthropic()

def run_agent_for_user(message: str, user) -> str:
    tools = get_tools_for_user(user)  # only permitted tools visible to model
    messages = [{"role": "user", "content": message}]
    system = f"You are an assistant for {user.email}. Your role is {', '.join(user.roles)}."

    while True:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=800,
            tools=tools,
            system=system,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next((b.text for b in resp.content if b.type == "text"), "")

        tool_results = []
        for block in resp.content:
            if block.type != "tool_use":
                continue
            # Defense in depth: check permission again at execution time
            if not check_tool_permission(block.name, user):
                result = json.dumps({"error": "permission_denied", "tool": block.name})
            else:
                result = execute_tool(block.name, block.input, user=user)
            tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})

        messages += [
            {"role": "assistant", "content": resp.content},
            {"role": "user", "content": tool_results},
        ]

def execute_tool(name: str, inputs: dict, user) -> str:
    """All tool functions receive the user context and filter results to that user's data."""
    if name == "search_knowledge_base":
        # In a real implementation, filter by tenant_id / user_id
        return json.dumps({"results": [f"Result for {user.sub}: ..."]})
    if name == "create_ticket":
        return json.dumps({"ticket_id": "TKT-001", "created_by": user.email})
    if name == "delete_record":
        # Extra caution: log who deleted what
        print(f"AUDIT: {user.email} deleted {inputs['record_id']}")
        return json.dumps({"deleted": inputs["record_id"]})
    return json.dumps({"error": "unknown tool"})

import time, threading, httpx
from jose import jwt, JWTError

class JWKSCache:
    def __init__(self, uri: str, ttl_seconds: int = 300):
        self._uri = uri
        self._ttl = ttl_seconds
        self._keys = None
        self._fetched_at = 0.0
        self._lock = threading.Lock()

    def get_keys(self, force_refresh: bool = False) -> dict:
        with self._lock:
            now = time.time()
            if force_refresh or self._keys is None or (now - self._fetched_at) > self._ttl:
                resp = httpx.get(self._uri, timeout=5)
                resp.raise_for_status()
                self._keys = resp.json()
                self._fetched_at = now
        return self._keys

    def decode(self, token: str, **kwargs) -> dict:
        try:
            return jwt.decode(token, self.get_keys(), **kwargs)
        except JWTError:
            # Key rotation: refresh once and retry
            return jwt.decode(token, self.get_keys(force_refresh=True), **kwargs)

# Shared cache instance for the process
jwks_cache = JWKSCache(uri="https://auth.example.com/.well-known/jwks.json")
